"use client";

import { useState, useRef, useEffect } from "react";
import { useRouter } from "next/navigation";
import { useAuth } from "@/context/AuthContext";
import {
  Heart,
  ArrowLeft,
  Send,
  Loader2,
  Sparkles,
  User,
  Bot,
  Globe,
} from "lucide-react";

interface Message {
  role: "user" | "assistant";
  content: string;
}

export default function AIAssistantPage() {
  const router = useRouter();
  const { user, isLoading } = useAuth();

  const [messages, setMessages] = useState<Message[]>([
    {
      role: "assistant",
      content:
        "Hello! I am your HealthBridge AI Concierge. I can help recommend partner hospitals, evaluate estimated procedure costs, or explain health insurance coverages. How can I support your healthcare search today?",
    },
  ]);

  const [input, setInput] = useState("");
  const [sending, setSending] = useState(false);
  const [lang, setLang] = useState<"en" | "hi">("en");

  const chatEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages]);

  const handleSend = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim() || sending) return;

    const userText = input.trim();
    setInput("");
    setMessages((prev) => [...prev, { role: "user", content: userText }]);
    setSending(true);

    try {
      const res = await fetch("/api/ai/chat", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          messages: [...messages, { role: "user", content: userText }].map((m) => ({
            role: m.role,
            content: m.content,
          })),
          lang,
        }),
      });

      const data = await res.json();
      if (data.success && data.data.message) {
        setMessages((prev) => [...prev, data.data.message]);
      } else {
        setMessages((prev) => [
          ...prev,
          {
            role: "assistant",
            content: "Sorry, I am facing connectivity issues. Please try again in a few seconds.",
          },
        ]);
      }
    } catch (err) {
      console.error(err);
      setMessages((prev) => [
        ...prev,
        {
          role: "assistant",
          content: "Failed to connect to the medical knowledge base. Check your internet settings.",
        },
      ]);
    } finally {
      setSending(false);
    }
  };

  const handlePromptClick = (prompt: string) => {
    setInput(prompt);
  };

  if (isLoading) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-surface-secondary">
        <Loader2 className="w-8 h-8 text-primary-600 animate-spin" />
      </div>
    );
  }

  const suggestionPrompts =
    lang === "en"
      ? [
          "Suggest a hospital in Mumbai for Cardiology.",
          "How much does Angioplasty cost at City General Hospital?",
          "Explain if PMJAY covers ICU rooms.",
        ]
      : [
          "मुंबई में कार्डियोलॉजी के लिए किसी अच्छे अस्पताल का नाम बताएं।",
          "सिटी जनरल हॉस्पिटल में एंजियोप्लास्टी का खर्च कितना है?",
          "क्या आयुष्मान योजना में आईसीयू बेड का खर्च शामिल है?",
        ];

  return (
    <div className="min-h-screen bg-surface-secondary flex flex-col justify-between">
      {/* Header */}
      <header className="bg-white border-b border-border h-16 flex items-center justify-between px-4 sm:px-6 lg:px-8">
        <div className="flex items-center gap-3">
          <button
            onClick={() => router.push("/dashboard")}
            className="text-text-muted hover:text-text-primary p-2 -ml-2 rounded-lg hover:bg-surface-secondary transition-colors"
          >
            <ArrowLeft className="w-5 h-5" />
          </button>
          <div className="flex items-center gap-2">
            <div className="w-8 h-8 gradient-bg rounded-lg flex items-center justify-center">
              <Sparkles className="w-4 h-4 text-white" />
            </div>
            <span className="text-sm font-bold text-text-primary">AI Concierge Assistant</span>
          </div>
        </div>

        {/* Translation Toggle */}
        <div className="flex items-center bg-surface-secondary rounded-lg p-1 text-xs font-bold border border-border">
          <button
            onClick={() => setLang("en")}
            className={`px-2.5 py-1 rounded-md transition-all cursor-pointer ${
              lang === "en" ? "bg-white text-primary-700 shadow-xs" : "text-text-muted hover:text-text-primary"
            }`}
          >
            English
          </button>
          <button
            onClick={() => setLang("hi")}
            className={`px-2.5 py-1 rounded-md transition-all cursor-pointer ${
              lang === "hi" ? "bg-white text-primary-700 shadow-xs" : "text-text-muted hover:text-text-primary"
            }`}
          >
            हिन्दी
          </button>
        </div>
      </header>

      {/* Message Feed */}
      <div className="flex-1 overflow-y-auto max-w-4xl w-full mx-auto p-4 sm:p-6 space-y-6">
        {messages.map((m, i) => {
          const isUser = m.role === "user";
          return (
            <div
              key={i}
              className={`flex gap-3 max-w-[85%] sm:max-w-[75%] ${
                isUser ? "ml-auto flex-row-reverse" : "mr-auto"
              }`}
            >
              <div
                className={`w-8 h-8 rounded-full flex items-center justify-center flex-shrink-0 border ${
                  isUser
                    ? "bg-primary-50 border-primary-200 text-primary-700"
                    : "bg-surface-secondary border-border text-text-secondary"
                }`}
              >
                {isUser ? <User className="w-4 h-4" /> : <Bot className="w-4 h-4" />}
              </div>

              <div
                className={`rounded-2xl p-4 text-sm sm:text-base leading-relaxed ${
                  isUser
                    ? "bg-primary-600 text-white font-medium"
                    : "bg-white border border-border text-text-primary"
                }`}
              >
                {m.content}
              </div>
            </div>
          );
        })}
        {sending && (
          <div className="flex gap-3 mr-auto max-w-[75%]">
            <div className="w-8 h-8 rounded-full flex items-center justify-center bg-surface-secondary border border-border text-text-secondary">
              <Bot className="w-4 h-4" />
            </div>
            <div className="bg-white border border-border rounded-2xl px-4 py-3 flex items-center gap-2">
              <Loader2 className="w-4 h-4 animate-spin text-primary-600" />
              <span className="text-xs text-text-muted">AI is analyzing healthcare records...</span>
            </div>
          </div>
        )}
        <div ref={chatEndRef} />
      </div>

      {/* Prompt Suggestions */}
      {messages.length === 1 && (
        <div className="max-w-4xl w-full mx-auto px-4 sm:px-6 pb-2 text-xs flex flex-col gap-2">
          <span className="text-text-muted font-bold uppercase tracking-wider block">Suggested Questions</span>
          <div className="flex flex-wrap gap-2">
            {suggestionPrompts.map((prompt) => (
              <button
                key={prompt}
                onClick={() => handlePromptClick(prompt)}
                className="text-left px-3 py-2 bg-white hover:bg-surface-secondary border border-border rounded-xl font-medium text-text-secondary cursor-pointer transition-colors"
              >
                {prompt}
              </button>
            ))}
          </div>
        </div>
      )}

      {/* Input bar */}
      <footer className="bg-white border-t border-border p-4 sticky bottom-0">
        <form onSubmit={handleSend} className="max-w-4xl w-full mx-auto flex gap-3">
          <input
            type="text"
            placeholder={
              lang === "en"
                ? "Ask about symptoms, costs, hospitals..."
                : "लक्षणों, खर्च या अस्पतालों के बारे में पूछें..."
            }
            value={input}
            onChange={(e) => setInput(e.target.value)}
            disabled={sending}
            className="flex-1 text-sm sm:text-base border border-border rounded-2xl px-4 py-3 bg-white text-text-primary focus:outline-none focus:border-primary-400 focus:ring-1 focus:ring-primary-400 transition-all shadow-xs placeholder-text-muted"
          />
          <button
            type="submit"
            disabled={!input.trim() || sending}
            className="p-3 bg-primary-600 hover:bg-primary-700 text-white rounded-2xl transition-all shadow-xs cursor-pointer disabled:opacity-50"
          >
            <Send className="w-5 h-5" />
          </button>
        </form>
      </footer>
    </div>
  );
}
